# tools/link_report.py — join BDD results with eval scores
import json
from pathlib import Path

bdd_results = {r["scenario_id"]: r
               for f in Path("bdd-results").glob("*.json")
               for r in [json.loads(f.read_text())]}

eval_scores = {r["id"]: r
               for f in Path("eval-results/latest").glob("*.jsonl")
               for r in [json.loads(line) for line in f.read_text().splitlines()]}

# Cross-reference
for scenario_id, bdd in bdd_results.items():
    eval_id = bdd.get("eval_id")
    if eval_id and eval_id in eval_scores:
        eval_r = eval_scores[eval_id]
        status = "✓" if bdd["verdict"] == "PASS" else "✗"
        print(f"{status} BDD {scenario_id} | Eval {eval_id}: "
              f"score={eval_r.get('score', '?'):.2f}")

# eval/drift_alert.py
"""Alert when an eval score linked to a BDD scenario drops more than threshold."""
import json
from pathlib import Path
from collections import defaultdict

DRIFT_THRESHOLD = 0.05   # alert if score drops > 5% vs 14-day average

# Load last 14 days of eval results
results_dir = Path("eval-results")
by_id = defaultdict(list)
for f in sorted(results_dir.glob("*.jsonl"))[-14:]:
    for line in f.read_text().splitlines():
        r = json.loads(line)
        by_id[r["id"]].append(r["score"])

# Load today's eval results
today_results = {
    r["id"]: r["score"]
    for line in Path("eval-results/today.jsonl").read_text().splitlines()
    for r in [json.loads(line)]
}

alerts = []
for eval_id, history in by_id.items():
    if len(history) < 7:
        continue   # Not enough history
    baseline = sum(history) / len(history)
    today = today_results.get(eval_id)
    if today is None:
        continue
    drift = baseline - today
    if drift >= DRIFT_THRESHOLD:
        alerts.append({
            "eval_id": eval_id,
            "baseline": round(baseline, 3),
            "today": round(today, 3),
            "drift": round(drift, 3),
        })

if alerts:
    print(f"DRIFT ALERT: {len(alerts)} eval score(s) dropped > {DRIFT_THRESHOLD:.0%}")
    for a in sorted(alerts, key=lambda x: -x["drift"]):
        print(f"  {a['eval_id']}: {a['baseline']:.3f} → {a['today']:.3f} "
              f"(↓{a['drift']:.3f})")
    raise SystemExit(1)
else:
    print(f"No drift detected across {len(by_id)} tracked eval IDs.")
